parameters.jsCode:
const clamp = (n, min, max) => Math.max(min, Math.min(max, n));
const asNum = (v, def = 0) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : def;
};

// Use EXACT names from your input item
const totalAssignments = asNum($json.totalAssignments, 0);
const totalJobsWithHires = asNum($json.totalJobsWithHires, 0);
const score5 = asNum($json.score, 0); // <-- your rating is "score"
const spend = asNum($json.totalCharges, 0); // <-- nested amount

// Normalize
const rating01 = clamp((score5 || 4.0) / 5, 0, 1);
const hireRate01 = totalAssignments > 0 ? clamp(totalJobsWithHires / totalAssignments, 0, 1) : 0.6;
const normalizedSpend01 = clamp(spend / 10000, 0, 1);
const repeatHireRate01 = 0.3;

// If you have this field, use it; otherwise keep 0
const paymentVerified01 = $json['isPaymentMethodVerified '] === true ? 1 : 0;

// Weighted (0..1)
const clientScore01 =
  (0.35 * rating01) +
  (0.25 * hireRate01) +
  (0.20 * normalizedSpend01) +
  (0.10 * repeatHireRate01) +
  (0.10 * paymentVerified01);

// Final (0..5)
const clientScore = Number((clientScore01 * 5).toFixed(2));

return {
  ...$json,
  debug: { rating01, hireRate01, normalizedSpend01, repeatHireRate01, paymentVerified01, clientScore01 },
  clientScore
};

